@RestController
@RequestMapping("/api/events")
class EventController {

    private final EventProducerService eventProducerService;

    EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping("/{topic}")
    public ResponseEntity<Map<String, Object>> publishEvent(
            @PathVariable String topic,
            @RequestHeader Map<String, String> requestHeaders,
            @RequestBody EventRequest request
    ) {
        String eventId = UUID.randomUUID().toString();
        eventProducerService.send(topic, request.getKey(), request.getPayload(), requestHeaders, eventId);

        Map<String, Object> response = new HashMap<>();
        response.put("status", "accepted");
        response.put("eventId", eventId);
        response.put("topic", topic);
        response.put("timestamp", Instant.now().toString());

        return ResponseEntity.status(HttpStatus.ACCEPTED).body(response);
    }
}

@Service
class EventProducerService {

    private final KafkaProducer<String, String> producer;

    EventProducerService(KafkaProducer<String, String> producer) {
        this.producer = producer;
    }

    public void send(String topic, String key, String payload, Map<String, String> httpHeaders, String eventId) {
        ProducerRecord<String, String> record = new ProducerRecord<>(topic, key, payload);
        Headers headers = record.headers();

        addHeaderIfPresent(headers, "tracking-id", httpHeaders.get("tracking-id"));
        addHeaderIfPresent(headers, "user-id", httpHeaders.get("user-id"));
        addHeaderIfPresent(headers, "x-request-id", httpHeaders.get("x-request-id"));
        addHeaderIfPresent(headers, "event-id", eventId);

        for (Map.Entry<String, String> entry : httpHeaders.entrySet()) {
            String headerName = entry.getKey();
            String headerValue = entry.getValue();

            if (headerName == null || headerValue == null) {
                continue;
            }

            if (isAllowedCustomHeader(headerName)) {
                headers.add(headerName, headerValue.getBytes(StandardCharsets.UTF_8));
            }
        }

        producer.send(record, new ProducerCallback(topic, key, eventId));
    }

    private void addHeaderIfPresent(Headers headers, String key, String value) {
        if (value != null && !value.isBlank()) {
            headers.add(key, value.getBytes(StandardCharsets.UTF_8));
        }
    }

    private boolean isAllowedCustomHeader(String headerName) {
        String normalized = headerName.toLowerCase();
        return normalized.startsWith("x-meta-")
                || normalized.startsWith("x-custom-")
                || normalized.equals("tracking-id")
                || normalized.equals("user-id")
                || normalized.equals("correlation-id");
    }

    @PreDestroy
    public void shutdown() {
        producer.flush();
        producer.close();
    }
}

class ProducerCallback implements Callback {

    private final String topic;
    private final String key;
    private final String eventId;

    ProducerCallback(String topic, String key, String eventId) {
        this.topic = topic;
        this.key = key;
        this.eventId = eventId;
    }

    @Override
    public void onCompletion(RecordMetadata metadata, Exception exception) {
        if (exception != null) {
            System.err.println("Failed to publish eventId=" + eventId + ", topic=" + topic + ", key=" + key + ", error=" + exception.getMessage());
            return;
        }

        System.out.println(
                "Published eventId=" + eventId +
                        ", topic=" + metadata.topic() +
                        ", partition=" + metadata.partition() +
                        ", offset=" + metadata.offset()
        );
    }
}

